-- ═══════════════════════════════════════════════════
-- JOHN CHAPTER 14 — I Am the Way, the Truth, and the Life; The Promise of the Paraclete
-- 31 verses · Greek text · Word studies · Cross-refs
-- ═══════════════════════════════════════════════════

-- Step 1: Insert chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 14,
  'John 14 is one of the most beloved chapters in the Bible — the opening of the Upper Room Discourse (chapters 14-16) that Jesus delivers on the last night of his earthly life. It is spoken to eleven frightened, confused disciples who face the imminent departure of their Lord. The chapter opens with the great pastoral command: ''Let not your heart be troubled'' (v.1) — a command grounded in faith: ''ye believe in God, believe also in me.'' Jesus speaks of going to prepare a place for the disciples in the Father''s house, and promises to return and receive them (vv.1-3). Thomas''s question — ''Lord, we know not whither thou goest; and how can we know the way?'' — draws the most famous reply in John: ''I am the way, the truth, and the life: no man cometh unto the Father, but by me'' (v.6). Philip''s request — ''shew us the Father, and it sufficeth us'' — receives the profound response: ''He that hath seen me hath seen the Father'' (v.9). Jesus promises that the disciples will do ''greater works'' because he goes to the Father (v.12). He commits to answering prayer in his name (vv.13-14). He introduces the Paraclete — the Holy Spirit, the Comforter, the Spirit of truth — who will be ''another Comforter'' (allon Paraklēton — another of the same kind) to be with them forever (vv.15-17). He promises the mutual indwelling of Father, Son, and believer (vv.18-23). Judas (not Iscariot) asks why Jesus manifests himself to the disciples and not to the world — Jesus replies that love and obedience are the condition of divine manifestation (vv.22-24). The chapter closes with the gift of peace — ''my peace I give unto you: not as the world giveth, give I unto you'' (v.27) — and the final call not to be troubled or afraid, because Jesus goes to the Father and the victory is already won (vv.28-31).',
  'I Am the Way — The Father Revealed in the Son by the Spirit',
  'παράκλητος (paraklētos)',
  'Advocate, Helper, Comforter, Counsellor — from para (beside) + kaleō (to call). One called alongside to help, an advocate in court, a counsellor in time of need. The word appears 5 times in John (14:16,26; 15:26; 16:7 — for the Spirit; and 1 John 2:1 — for Christ as our advocate with the Father). Jesus calls the Spirit ''another Comforter'' (allon Paraklēton — another of the same kind), implying that Jesus himself is the first Paraclete. The Spirit continues Christ''s ministry: teaching, reminding, testifying, convicting, guiding. He is not an impersonal force but a person who can be grieved (Ephesians 4:30), who speaks, who prays, who wills (1 Corinthians 12:11). The promise of the Paraclete is the answer to the disciples'' anxiety about Jesus''s departure.',
  '["The Father''s House (vv.1-4): Let not your heart be troubled ye believe in God believe also in me. In my Father''s house are many mansions if it were not so I would have told you. I go to prepare a place for you. And if I go and prepare a place for you I will come again and receive you unto myself that where I am there ye may be also. And whither I go ye know and the way ye know","I Am the Way, the Truth, and the Life (vv.5-7): Thomas saith unto him Lord we know not whither thou goest and how can we know the way? Jesus saith unto him I am the way the truth and the life no man cometh unto the Father but by me. If ye had known me ye should have known my Father also and from henceforth ye know him and have seen him","Philip''s Request (vv.8-14): Philip saith unto him Lord shew us the Father and it sufficeth us. Jesus saith unto him Have I been so long time with you and yet hast thou not known me Philip? he that hath seen me hath seen the Father and how sayest thou then Shew us the Father? Believest thou not that I am in the Father and the Father in me? the words that I speak unto you I speak not of myself but the Father that dwelleth in me he doeth the works. Believe me that I am in the Father and the Father in me or else believe me for the very works'' sake. Verily verily I say unto you He that believeth on me the works that I do shall he do also and greater works than these shall he do because I go unto my Father. And whatsoever ye shall ask in my name that will I do that the Father may be glorified in the Son. If ye shall ask any thing in my name I will do it","The Promise of the Paraclete (vv.15-17): If ye love me keep my commandments. And I will pray the Father and he shall give you another Comforter that he may abide with you for ever even the Spirit of truth whom the world cannot receive because it seeth him not neither knoweth him but ye know him for he dwelleth with you and shall be in you","The Mutual Indwelling (vv.18-24): I will not leave you comfortless I will come to you. Yet a little while and the world seeth me no more but ye see me because I live ye shall live also. At that day ye shall know that I am in my Father and ye in me and I in you. He that hath my commandments and keepeth them he it is that loveth me and he that loveth me shall be loved of my Father and I will love him and will manifest myself to him. Judas saith unto him not Iscariot Lord how is it that thou wilt manifest thyself unto us and not unto the world? Jesus answered and said unto him If a man love me he will keep my words and my Father will love him and we will come unto him and make our abode with him","Peace and the Return (vv.25-31): These things have I spoken unto you being yet present with you. But the Comforter which is the Holy Ghost whom the Father will send in my name he shall teach you all things and bring all things to your remembrance whatsoever I have said unto you. Peace I leave with you my peace I give unto you not as the world giveth give I unto you. Let not your heart be troubled neither let it be afraid. Ye have heard how I said unto you I go away and come again unto you. If ye loved me ye would rejoice because I said I go unto the Father for my Father is greater than I. And now I have told you before it come to pass that when it is come to pass ye might believe. Hereafter I will not talk much with you for the prince of this world cometh and hath nothing in me. But that the world may know that I love the Father and as the Father gave me commandment even so I do Arise let us go hence"]'
FROM books b WHERE b.name = 'John';

-- Step 2: Insert all 31 verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Let not your heart be troubled: ye believe in God, believe also in me.',
   'Μὴ ταρασσέσθω ὑμῶν ἡ καρδία πιστεύετε εἰς τὸν θεὸν καὶ εἰς ἐμὲ πιστεύετε',
   'Mē tarassesthō hymōn hē kardia pisteuete eis ton theon kai eis eme pisteuete',
   '''Let not your heart be troubled'' (mē tarassesthō hymōn hē kardia — do not let your heart be disturbed/shaken; tarassō: to agitate, throw into confusion). The disciples are in anguish: Jesus has announced his departure (13:33), his death, and Peter''s denial. The command is grounded in faith — ''ye believe in God, believe also in me'' (pisteuete eis ton theon kai eis eme pisteuete). Both ''believe''s may be indicative (''you believe in God, you believe also in me'') or both imperatives, or the first indicative and the second imperative. In any reading, faith in God and faith in Christ are co-extensive. Anxiety is conquered not by circumstances but by trust in the one who controls circumstances.',
   NULL),
  (2, 'In my Father''s house are many mansions: if it were not so, I would have told you. I go to prepare a place for you.',
   'ἐν τῇ οἰκίᾳ τοῦ πατρός μου μοναὶ πολλαί εἰσιν εἰ δὲ μή εἶπον ἂν ὑμῖν ὅτι πορεύομαι ἑτοιμάσαι τόπον ὑμῖν',
   'en tē oikia tou patros mou monai pollai eisin ei de mē eipon an hymin hoti poreuomai hetoimasai topon hymin',
   '''In my Father''s house are many mansions'' (en tē oikia tou patros mou monai pollai eisin — in my Father''s house there are many dwelling places). ''Monai'' (plural of monē — from menō: to abide, remain; a staying-place, a dwelling). The KJV''s ''mansions'' (from Latin mansiones) can mislead: it is not palatial grandeur but permanent, settled dwelling — a home, not a hotel. ''Many'' (pollai — many, ample room for all). ''I go to prepare a place for you'' (poreuomai hetoimasai topon hymin) — Jesus'' departure is purposeful: he goes as the forerunner (Hebrews 6:20) to prepare the dwelling for those who follow.',
   NULL),
  (3, 'And if I go and prepare a place for you, I will come again, and receive you unto myself; that where I am, there ye may be also.',
   'καὶ ἐὰν πορευθῶ καὶ ἑτοιμάσω τόπον ὑμῖν πάλιν ἔρχομαι καὶ παραλήμψομαι ὑμᾶς πρὸς ἐμαυτόν ἵνα ὅπου εἰμὶ ἐγὼ καὶ ὑμεῖς ἦτε',
   'kai ean poreuthō kai hetoimasō topon hymin palin erchomai kai paralēmpsomai hymas pros emauton hina hopou eimi egō kai hymeis ēte',
   '''I will come again'' (palin erchomai — I am coming again; the present tense expresses the certainty of the future event). This is one of the clearest promises of the Second Coming in John (cf. 21:22-23; Acts 1:11). ''Receive you unto myself'' (paralēmpsomai hymas pros emauton — will take you alongside to myself; paralambano: to take alongside, receive to oneself). ''That where I am, there ye may be also'' — the goal of salvation is not just escape from hell but eternal fellowship with Christ in the Father''s presence.',
   NULL),
  (4, 'And whither I go ye know, and the way ye know.',
   'καὶ ὅπου ἐγὼ ὑπάγω οἴδατε τὴν ὁδὸν οἴδατε',
   'kai hopou egō hypagō oidate tēn hodon oidate',
   'Jesus assumes the disciples know both the destination (the Father) and the way (himself). But Thomas will immediately reveal they do not understand. Jesus''s statement is not an oversight — it is a prompt to draw out the question that leads to the great ''I AM the way'' declaration.',
   NULL),
  (5, 'Thomas saith unto him, Lord, we know not whither thou goest; and how can we know the way?',
   'λέγει αὐτῷ Θωμᾶς Κύριε οὐκ οἴδαμεν ποῦ ὑπάγεις καὶ πῶς δυνάμεθα τὴν ὁδὸν εἰδέναι',
   'legei autō Thōmas Kyrie ouk oidamen pou hypageis kai pōs dynametha tēn hodon eidenai',
   'Thomas (Thōmas — Aramaic: twin; his Greek name is Didymus, 11:16; 20:24; 21:2) is consistently the disciple who raises honest, searching doubts (11:16; 20:24-25). His question is literal and confused: ''we do not know where you are going, so how can we know the way?'' It is precisely this honest incomprehension that draws from Jesus the most explicit statement of his exclusive mediatorship. Good questions receive great answers.',
   NULL),
  (6, 'Jesus saith unto him, I am the way, the truth, and the life: no man cometh unto the Father, but by me.',
   'λέγει αὐτῷ ὁ Ἰησοῦς Ἐγώ εἰμι ἡ ὁδὸς καὶ ἡ ἀλήθεια καὶ ἡ ζωή οὐδεὶς ἔρχεται πρὸς τὸν πατέρα εἰ μὴ δι᾽ ἐμοῦ',
   'legei autō ho Iēsous Egō eimi hē hodos kai hē alētheia kai hē zōē oudeis erchetai pros ton patera ei mē di emou',
   '''I am the way, the truth, and the life'' (Egō eimi hē hodos kai hē alētheia kai hē zōē) — the sixth of the seven great ''I AM'' declarations in John (6:35; 8:12; 10:9; 10:11; 11:25; 14:6; 15:1). All three nouns have the definite article: not ''a'' way, ''a'' truth, ''a'' life, but THE way, THE truth, THE life — exclusive and definitive. The three terms are not three separate things but one threefold reality: Jesus is the way because he is the truth; he is the truth because he is the life; he is the life because he is the way. ''No man cometh unto the Father, but by me'' (oudeis erchetai pros ton patera ei mē di emou) — the most explicit statement of exclusive salvation in the New Testament. Not arrogance but ontological necessity: only the Son can bring us to the Father because only the Son knows the Father (v.7; Matthew 11:27).',
   NULL),
  (7, 'If ye had known me, ye should have known my Father also: and from henceforth ye know him, and have seen him.',
   'εἰ ἐγνώκατέ με καὶ τὸν πατέρα μου γνώσεσθε καὶ ἀπ᾽ ἄρτι γινώσκετε αὐτὸν καὶ ἑωράκατε αὐτόν',
   'ei egnōkate me kai ton patera mou gnōsesthe kai ap arti ginōskete auton kai heōrakate auton',
   '''If ye had known me, ye should have known my Father also'' — the knowledge of Christ is the knowledge of God. The disciples have been with Jesus for three years; they have seen the Father through him, though they have not realised it. ''From henceforth ye know him, and have seen him'' (ap arti ginōskete auton kai heōrakate auton — from now on you know him and have seen him). The disclosure is now complete: the departure of Jesus and the coming of the Spirit will make this knowledge conscious and articulate.',
   NULL),
  (8, 'Philip saith unto him, Lord, shew us the Father, and it sufficeth us.',
   'λέγει αὐτῷ Φίλιππος Κύριε δεῖξον ἡμῖν τὸν πατέρα καὶ ἀρκεῖ ἡμῖν',
   'legei autō Philippos Kyrie deixon hēmin ton patera kai arkei hēmin',
   'Philip (like Thomas) raises an earnest question: ''Shew us the Father, and it sufficeth us'' (deixon hēmin ton patera kai arkei hēmin — show us the Father, and this is enough for us). Philip wants a theophany — a direct vision of God like Moses at Sinai or Isaiah in the temple. His request is not unreasonable; it is simply that he does not recognise what has already been given. He has had three years of theophany — the Father has been visible in the Son throughout.',
   NULL),
  (9, 'Jesus saith unto him, Have I been so long time with you, and yet hast thou not known me, Philip? he that hath seen me hath seen the Father; and how sayest thou then, Shew us the Father?',
   'λέγει αὐτῷ ὁ Ἰησοῦς Τοσοῦτον χρόνον μεθ᾽ ὑμῶν εἰμι καὶ οὐκ ἔγνωκάς με Φίλιππε ὁ ἑωρακὼς ἐμὲ ἑώρακεν τὸν πατέρα καὶ πῶς σὺ λέγεις Δεῖξον ἡμῖν τὸν πατέρα',
   'legei autō ho Iēsous Tosouton chronon meth hymōn eimi kai ouk egnōkas me Philippe ho heōrakōs eme heōraken ton patera kai pōs sy legeis Deixon hēmin ton patera',
   '''He that hath seen me hath seen the Father'' (ho heōrakōs eme heōraken ton patera — the one who has seen me has seen the Father; perfect tenses: the seeing has occurred and the result stands). This is the summit of Johannine Christology: Jesus is not merely a messenger from the Father or a window through which the Father can be partly glimpsed; he is the full and perfect image of the Father (Colossians 1:15; Hebrews 1:3). To have seen Jesus is to have seen God. The incarnation is the definitive theophany.',
   NULL),
  (10, 'Believest thou not that I am in the Father, and the Father in me? the words that I speak unto you I speak not of myself: but the Father that dwelleth in me, he doeth the works.',
   'οὐ πιστεύεις ὅτι ἐγὼ ἐν τῷ πατρὶ καὶ ὁ πατὴρ ἐν ἐμοί ἐστιν τὰ ῥήματα ἃ ἐγὼ λαλῶ ὑμῖν ἀπ᾽ ἐμαυτοῦ οὐ λαλῶ ὁ δὲ πατὴρ ἐν ἐμοὶ μένων αὐτὸς ποιεῖ τὰ ἔργα',
   'ou pisteueis hoti egō en tō patri kai ho patēr en emoi estin ta rhēmata ha egō lalō hymin ap emautou ou lalō ho de patēr en emoi menōn autos poiei ta erga',
   '''I am in the Father, and the Father in me'' (egō en tō patri kai ho patēr en emoi) — mutual indwelling, perichoresis (the theological term for the mutual interpenetration of the Trinity). This is not identity (the Father and Son are distinct persons) but perfect union of will, knowledge, and being. ''The Father that dwelleth in me, he doeth the works'' (ho patēr en emoi menōn autos poiei ta erga) — the miracles of Jesus are the Father''s works performed through the Son. The Son acts, the Father acts in him; they are inseparable in operation.',
   NULL),
  (11, 'Believe me that I am in the Father, and the Father in me: or else believe me for the very works'' sake.',
   'πιστεύετέ μοι ὅτι ἐγὼ ἐν τῷ πατρὶ καὶ ὁ πατὴρ ἐν ἐμοί εἰ δὲ μή διὰ τὰ ἔργα αὐτὰ πιστεύετε',
   'pisteuete moi hoti egō en tō patri kai ho patēr en emoi ei de mē dia ta erga auta pisteuete',
   '''Believe me for the very works'' sake'' (dia ta erga auta pisteuete — believe because of the works themselves). Jesus offers two grounds for faith: his word and his works. Ideally faith accepts the word of Christ as sufficient; if not, the miracles provide secondary, visible evidence. The argument mirrors 5:36: ''the works which the Father hath given me to finish, the same works that I do, bear witness of me.'' Faith based on miracles is accepted, though not as highly commended as faith based on the word alone (20:29).',
   NULL),
  (12, 'Verily, verily, I say unto you, He that believeth on me, the works that I do shall he do also; and greater works than these shall he do; because I go unto my Father.',
   'ἀμὴν ἀμὴν λέγω ὑμῖν ὁ πιστεύων εἰς ἐμὲ τὰ ἔργα ἃ ἐγὼ ποιῶ κἀκεῖνος ποιήσει καὶ μείζονα τούτων ποιήσει ὅτι ἐγὼ πρὸς τὸν πατέρα πορεύομαι',
   'amēn amēn legō hymin ho pisteuōn eis eme ta erga ha egō poiō kakeinos poiēsei kai meizona toutōn poiēsei hoti egō pros ton patera poreuomai',
   '''Greater works than these shall he do'' (meizona toutōn poiēsei — greater things than these he will do). The ''greater works'' are not superior miracles (as if healings better than Jesus''s) but greater in scope and scale: the mission of the church through the Spirit would reach the whole world (Acts 1:8), bringing thousands to salvation (Acts 2:41; 4:4). Jesus''s ministry was geographically confined to Israel; the disciples'' ministry, empowered by the Spirit, would be universal. ''Because I go unto my Father'' — the departure of Jesus and the coming of the Spirit is the enabling condition of the greater works.',
   NULL),
  (13, 'And whatsoever ye shall ask in my name, that will I do, that the Father may be glorified in the Son.',
   'καὶ ὅ τι ἂν αἰτήσητε ἐν τῷ ὀνόματί μου τοῦτο ποιήσω ἵνα δοξασθῇ ὁ πατὴρ ἐν τῷ υἱῷ',
   'kai ho ti an aitēsēte en tō onomati mou touto poiēsō hina doxasthē ho patēr en tō huiō',
   '''Whatsoever ye shall ask in my name'' (ho ti an aitēsēte en tō onomati mou — whatever you ask in my name). ''In my name'' (en tō onomati mou) is not a formula appended to prayer but praying in accordance with Christ''s character, will, and authority — as his representatives, on his behalf, for his purposes. The promise is expansive but not blank: ''in my name'' excludes selfish, faithless, or contrary-to-God''s-will requests (James 4:3; 1 John 5:14). The purpose: ''that the Father may be glorified in the Son'' — answered prayer is doxological; it brings glory to God.',
   NULL),
  (14, 'If ye shall ask any thing in my name, I will do it.',
   'ἐάν τι αἰτήσητέ με ἐν τῷ ὀνόματί μου ἐγὼ ποιήσω',
   'ean ti aitēsēte me en tō onomati mou egō poiēsō',
   'The promise is repeated with slight variation — ''ask me'' (aitēsēte me — ask me directly; Jesus himself as the answerer of prayer). This confirms that prayer to Jesus is prayer to God; he is not merely an intermediary but the one addressed. The repetition (vv.13-14) emphasises the certainty and the personal involvement of Christ in prayer.',
   NULL),
  (15, 'If ye love me, keep my commandments.',
   'Ἐὰν ἀγαπᾶτέ με τὰς ἐντολὰς τὰς ἐμὰς τηρήσετε',
   'Ean agapate me tas entolas tas emas tērēsete',
   '''If ye love me, keep my commandments'' (ean agapate me, tas entolas tas emas tērēsete — if you love me, you will keep my commandments). Love is not primarily an emotion but an orientation of the will that produces obedience. ''Keep'' (tērēsete — you will keep; future indicative, not imperative: this is a prediction arising from love, not merely a command). If love is genuine, obedience follows naturally. The commandments are not burdens imposed from without but the natural expression of love for Christ (1 John 5:3). This is the fulfilment of the New Covenant promise: the law written on the heart (Jeremiah 31:33).',
   NULL),
  (16, 'And I will pray the Father, and he shall give you another Comforter, that he may abide with you for ever;',
   'κἀγὼ ἐρωτήσω τὸν πατέρα καὶ ἄλλον παράκλητον δώσει ὑμῖν ἵνα μένῃ μεθ᾽ ὑμῶν εἰς τὸν αἰῶνα',
   'kagō erōtēsō ton patera kai allon paraklēton dōsei hymin hina menē meth hymōn eis ton aiōna',
   '''Another Comforter'' (allon paraklēton — another of the same kind of Paraclete; allos: another of the same kind, vs. heteros: another of a different kind). The Spirit is another Paraclete because Jesus is the first — 1 John 2:1 calls Christ our Paraklētos with the Father. The Spirit continues and internalises what Christ did externally. ''That he may abide with you for ever'' (hina menē meth hymōn eis ton aiōna — so that he may remain with you into the age). Jesus'' bodily presence was temporary; the Spirit''s presence is permanent. No disciples have lost the Spirit; he abides with them forever.',
   NULL),
  (17, 'Even the Spirit of truth; whom the world cannot receive, because it seeth him not, neither knoweth him: but ye know him; for he dwelleth with you, and shall be in you.',
   'τὸ πνεῦμα τῆς ἀληθείας ὃ ὁ κόσμος οὐ δύναται λαβεῖν ὅτι οὐ θεωρεῖ αὐτὸ οὐδὲ γινώσκει αὐτό ὑμεῖς δὲ γινώσκετε αὐτό ὅτι παρ᾽ ὑμῖν μένει καὶ ἐν ὑμῖν ἔσται',
   'to pneuma tēs alētheias ho ho kosmos ou dynatai labein hoti ou theōrei auto oude ginōskei auto hymeis de ginōskete auto hoti par hymin menei kai en hymin estai',
   '''The Spirit of truth'' (to pneuma tēs alētheias) — the Spirit''s defining characteristic is truth; he guides into all truth (16:13), witnesses to the truth (15:26), is identified with truth (1 John 5:6). ''The world cannot receive'' (ho kosmos ou dynatai labein) — the world is constitutionally incapable of receiving the Spirit of truth, because it does not see or know him. The Spirit is spiritually discerned (1 Corinthians 2:14). ''He dwelleth with you, and shall be in you'' — a progressive movement: with (para: alongside, the Spirit''s presence with Jesus and the disciples during his ministry) → in (en: within, after Pentecost).',
   NULL),
  (18, 'I will not leave you comfortless: I will come to you.',
   'Οὐκ ἀφήσω ὑμᾶς ὀρφανούς ἔρχομαι πρὸς ὑμᾶς',
   'Ouk aphēsō hymas orphanous erchomai pros hymas',
   '''I will not leave you comfortless'' (ouk aphēsō hymas orphanous — I will not leave you as orphans). ''Orphanous'' (orphans — from orphanos: bereaved of a parent or teacher; used for disciples bereft of their rabbi). Jesus will not abandon the disciples as helpless orphans. ''I will come to you'' (erchomai pros hymas — I am coming to you; present tense of certainty). This coming may refer to: (1) the resurrection appearances; (2) the coming of the Spirit (vv.16-17, 23); (3) the Second Coming. All three are likely in view as a telescoping fulfilment.',
   NULL),
  (19, 'Yet a little while, and the world seeth me no more; but ye see me: because I live, ye shall live also.',
   'ἔτι μικρὸν καὶ ὁ κόσμος με οὐκέτι θεωρεῖ ὑμεῖς δὲ θεωρεῖτέ με ὅτι ἐγὼ ζῶ καὶ ὑμεῖς ζήσετε',
   'eti mikron kai ho kosmos me ouketi theōrei hymeis de theōreite me hoti egō zō kai hymeis zēsete',
   '''The world seeth me no more'' (ho kosmos me ouketi theōrei — the world no longer beholds me). After the resurrection, Jesus does not appear to the world at large — only to the disciples (Acts 10:40-41). ''But ye see me'' (hymeis de theōreite me — you see/behold me; theōreō: a sustained, perceptive beholding, not a glance). ''Because I live, ye shall live also'' (hoti egō zō kai hymeis zēsete) — the resurrection life of Christ is the foundation of the disciples'' resurrection life. His life is the source of theirs; they live because he lives (cf. Galatians 2:20; Colossians 3:4).',
   NULL),
  (20, 'At that day ye shall know that I am in my Father, and ye in me, and I in you.',
   'ἐν ἐκείνῃ τῇ ἡμέρᾳ γνώσεσθε ὑμεῖς ὅτι ἐγὼ ἐν τῷ πατρί μου καὶ ὑμεῖς ἐν ἐμοὶ κἀγὼ ἐν ὑμῖν',
   'en ekeinē tē hēmera gnōsesthe hymeis hoti egō en tō patri mou kai hymeis en emoi kagō en hymin',
   '''At that day'' (en ekeinē tē hēmera — in that day; the day of resurrection, Pentecost, and the ongoing life in the Spirit). The Trinitarian indwelling extends to the believer: Father → Son → believer; and believer → Son → Father. ''Ye in me, and I in you'' — the mutual indwelling of Christ and the believer (cf. Galatians 2:20; Colossians 1:27; 1 John 4:13). This is the goal of salvation: union with God through union with Christ in the Spirit.',
   NULL),
  (21, 'He that hath my commandments, and keepeth them, he it is that loveth me: and he that loveth me shall be loved of my Father, and I will love him, and will manifest myself to him.',
   'ὁ ἔχων τὰς ἐντολάς μου καὶ τηρῶν αὐτὰς ἐκεῖνός ἐστιν ὁ ἀγαπῶν με ὁ δὲ ἀγαπῶν με ἀγαπηθήσεται ὑπὸ τοῦ πατρός μου καὶ ἐγὼ ἀγαπήσω αὐτὸν καὶ ἐμφανίσω αὐτῷ ἐμαυτόν',
   'ho echōn tas entolas mou kai tērōn autas ekeinos estin ho agapōn me ho de agapōn me agapēthēsetai hypo tou patros mou kai egō agapēsō auton kai emphanisō autō emauton',
   '''He that hath my commandments, and keepeth them, he it is that loveth me'' — love is defined by obedience, not merely by feeling. ''Having'' (echōn — possessing, knowing) and ''keeping'' (tērōn — guarding, obeying) are two dimensions: understanding and doing. ''I will manifest myself to him'' (emphanisō autō emauton — I will make myself visible/known to him). ''Emphanizō'' (to make manifest, to disclose). Jesus promises a personal, experiential disclosure of himself to the obedient lover — an interior manifestation through the Spirit (cf. v.23).',
   NULL),
  (22, 'Judas saith unto him, not Iscariot, Lord, how is it that thou wilt manifest thyself unto us, and not unto the world?',
   'λέγει αὐτῷ Ἰούδας οὐχ ὁ Ἰσκαριώτης Κύριε καὶ τί γέγονεν ὅτι ἡμῖν μέλλεις ἐμφανίζειν σεαυτὸν καὶ οὐχὶ τῷ κόσμῳ',
   'legei autō Ioudas ouch ho Iskariōtēs Kyrie kai ti gegonen hoti hēmin melleis emphanizein seauton kai ouchi tō kosmō',
   'Judas (not Iscariot) — distinguished from the betrayer; probably Judas son of James (Luke 6:16; Acts 1:13; also called Thaddaeus in Matthew/Mark). He voices the disciples'' continuing Jewish messianic expectation: the Messiah should manifest himself publicly, triumphantly, to the whole world. Why a private disclosure? The question reveals an expectation of a political, visible kingdom. Jesus'' answer reframes ''manifestation'': the presence of God is not given as an external spectacle to the world but as an internal indwelling to the obedient.',
   NULL),
  (23, 'Jesus answered and said unto him, If a man love me, he will keep my words: and my Father will love him, and we will come unto him, and make our abode with him.',
   'ἀπεκρίθη Ἰησοῦς καὶ εἶπεν αὐτῷ Ἐάν τις ἀγαπᾷ με τὸν λόγον μου τηρήσει καὶ ὁ πατήρ μου ἀγαπήσει αὐτὸν καὶ πρὸς αὐτὸν ἐλευσόμεθα καὶ μονὴν παρ᾽ αὐτῷ ποιησόμεθα',
   'apekrithē Iēsous kai eipen autō Ean tis agapā me ton logon mou tērēsei kai ho patēr mou agapēsei auton kai pros auton eleusometha kai monēn par autō poiēsometha',
   '''We will come unto him, and make our abode with him'' (pros auton eleusometha kai monēn par autō poiēsometha). ''Monēn'' — dwelling place (the same word as ''mansions'' in v.2). The Father''s house has many dwelling places; and the obedient believer''s heart is a dwelling place for the Father and Son. The indwelling of the Trinity in the believer is the deepest mystery of Christian experience. This is not merely forensic justification but ontological union — God making his home in the human heart. The condition: love expressed in keeping the word.',
   NULL),
  (24, 'He that loveth me not keepeth not my sayings: and the word which ye hear is not mine, but the Father''s which sent me.',
   'ὁ μὴ ἀγαπῶν με τοὺς λόγους μου οὐ τηρεῖ καὶ ὁ λόγος ὃν ἀκούετε οὐκ ἔστιν ἐμὸς ἀλλὰ τοῦ πέμψαντός με πατρός',
   'ho mē agapōn me tous logous mou ou tērei kai ho logos hon akouete ouk estin emos alla tou pempsantos me patros',
   'The negative corollary: absence of love produces disobedience. ''The word which ye hear is not mine, but the Father''s'' — a reminder (as in 12:49) that Jesus speaks entirely as the Father''s agent. To reject Jesus''s words is to reject the Father''s word. Disobedience to Christ is not merely a human failing but a rejection of God himself.',
   NULL),
  (25, 'These things have I spoken unto you, being yet present with you.',
   'Ταῦτα λελάληκα ὑμῖν παρ᾽ ὑμῖν μένων',
   'Tauta lelalēka hymin par hymin menōn',
   '''Being yet present with you'' (par hymin menōn — while remaining alongside you). The discourse is spoken while Jesus is physically present. He is preparing them for the time when he will no longer be physically present but the Comforter will take his place.',
   NULL),
  (26, 'But the Comforter, which is the Holy Ghost, whom the Father will send in my name, he shall teach you all things, and bring all things to your remembrance, whatsoever I have said unto you.',
   'ὁ δὲ παράκλητος τὸ πνεῦμα τὸ ἅγιον ὃ πέμψει ὁ πατὴρ ἐν τῷ ὀνόματί μου ἐκεῖνος ὑμᾶς διδάξει πάντα καὶ ὑπομνήσει ὑμᾶς πάντα ἃ εἶπον ὑμῖν ἐγώ',
   'ho de paraklētos to pneuma to hagion ho pempsει ho patēr en tō onomati mou ekeinos hymas didaxei panta kai hypomnēsei hymas panta ha eipon hymin egō',
   '''The Holy Ghost'' (to pneuma to hagion — the Holy Spirit; the name ''Holy Spirit'' appears here for the first time in John). ''Sent in my name'' (en tō onomati mou — in my name, as my representative and continuation). ''He shall teach you all things'' (ekeinos hymas didaxei panta — that one will teach you all things). ''Bring all things to your remembrance'' (hypomnēsei hymas panta — will remind you of all things). The two functions: (1) teaching new understanding of what has already been said; (2) reminding, calling to mind specific words of Jesus. This is the inspiration of the apostolic writings: the Spirit both reminded them of Jesus''s exact words and gave them the understanding to interpret those words rightly.',
   NULL),
  (27, 'Peace I leave with you, my peace I give unto you: not as the world giveth, give I unto you. Let not your heart be troubled, neither let it be afraid.',
   'Εἰρήνην ἀφίημι ὑμῖν εἰρήνην τὴν ἐμὴν δίδωμι ὑμῖν οὐ καθὼς ὁ κόσμος δίδωσιν ἐγὼ δίδωμι ὑμῖν μὴ ταρασσέσθω ὑμῶν ἡ καρδία μηδὲ δειλιάτω',
   'Eirēnēn aphiēmi hymin eirēnēn tēn emēn didōmi hymin ou kathōs ho kosmos didōsin egō didōmi hymin mē tarassesthō hymōn hē kardia mēde deiliatō',
   '''Peace I leave with you; my peace I give unto you'' (eirēnēn aphiēmi hymin; eirēnēn tēn emēn didōmi hymin). Departing guests would say ''I leave you peace'' — a conventional farewell. Jesus transforms the convention: ''my peace'' (tēn emēn — the definite, emphatic ''mine'') is qualitatively different from the world''s peace. The world''s peace is the absence of conflict; Christ''s peace is the shalom of the Hebrew Bible — completeness, wholeness, wellbeing in God. It is the peace he demonstrated in the storm (''Peace, be still''), in Gethsemane, on the cross. ''Not as the world giveth'' — the world''s peace depends on circumstances; Christ''s peace transcends them (Philippians 4:7). ''Neither let it be afraid'' (mēde deiliatō — nor let it be cowardly; deiliaō: to be timid, fearful; a word of moral cowardice).',
   NULL),
  (28, 'Ye have heard how I said unto you, I go away, and come again unto you. If ye loved me, ye would rejoice, because I said, I go unto the Father: for my Father is greater than I.',
   'ἠκούσατε ὅτι ἐγὼ εἶπον ὑμῖν Ὑπάγω καὶ ἔρχομαι πρὸς ὑμᾶς εἰ ἠγαπᾶτέ με ἐχάρητε ἄν ὅτι πορεύομαι πρὸς τὸν πατέρα ὅτι ὁ πατήρ μου μείζων μού ἐστιν',
   'ēkousate hoti egō eipon hymin Hypagō kai erchomai pros hymas ei ēgapate me echarēte an hoti poreuomai pros ton patera hoti ho patēr mou meizōn mou estin',
   '''My Father is greater than I'' (ho patēr mou meizōn mou estin) — this statement has been much debated. In context, Jesus is speaking from the perspective of his incarnate, earthly state: the Father is greater in terms of position and role within the economy of salvation. The Son, having voluntarily limited himself in the incarnation, goes to the Father who is greater in terms of the divine order of operations (1 Corinthians 15:28). This is an economic Trinitarian statement, not an ontological one — it does not deny the co-equality of Father and Son in essence (cf. 10:30: ''I and the Father are one'').',
   NULL),
  (29, 'And now I have told you before it come to pass, that, when it is come to pass, ye might believe.',
   'καὶ νῦν εἴρηκα ὑμῖν πρὶν γενέσθαι ἵνα ὅταν γένηται πιστεύσητε',
   'kai nyn eirēka hymin prin genesthai hina hotan genētai pisteusēte',
   'The purpose of prophecy: forewarning strengthens faith when the foretold event arrives. The disciples will recall these words after the resurrection and their faith will be confirmed rather than destroyed by the very events (arrest, crucifixion, apparent defeat) that seemed to contradict everything Jesus had taught.',
   NULL),
  (30, 'Hereafter I will not talk much with you: for the prince of this world cometh, and hath nothing in me.',
   'οὐκέτι πολλὰ λαλήσω μεθ᾽ ὑμῶν ἔρχεται γὰρ ὁ τοῦ κόσμου τούτου ἄρχων καὶ ἐν ἐμοὶ οὐκ ἔχει οὐδέν',
   'ouketi polla lalēsō meth hymōn erchetai gar ho tou kosmou toutou archōn kai en emoi ouk echei ouden',
   '''The prince of this world cometh'' (ho tou kosmou toutou archōn — the ruler of this world; Satan, cf. 12:31; 16:11). ''Hath nothing in me'' (en emoi ouk echei ouden — in me he has nothing). Satan has no claim on Jesus, no foothold, no point of access. Jesus is perfectly sinless; there is nothing in him that corresponds to Satan''s temptations or accusations. This is the ground of his victory on the cross: Satan has no legal or moral claim on the sinless one, yet the sinless one dies — and by that death defeats the one who held the power of death (Hebrews 2:14).',
   NULL),
  (31, 'But that the world may know that I love the Father; and as the Father gave me commandment, even so I do. Arise, let us go hence.',
   'ἀλλ᾽ ἵνα γνῷ ὁ κόσμος ὅτι ἀγαπῶ τὸν πατέρα καὶ καθὼς ἐντολὴν ἔδωκέν μοι ὁ πατήρ οὕτως ποιῶ ἐγείρεσθε ἄγωμεν ἐντεῦθεν',
   'all hina gnō ho kosmos hoti agapō ton patera kai kathōs entolēn edōken moi ho patēr houtōs poiō egeiresthe agōmen enteuthen',
   '''That the world may know that I love the Father'' (hina gnō ho kosmos hoti agapō ton patera) — the cross is not merely Jesus''s submission to death but his public demonstration of love for the Father. The Passion is the supreme act of filial obedience. ''As the Father gave me commandment, even so I do'' (kathōs entolēn edōken moi ho patēr, houtōs poiō) — perfect obedience. ''Arise, let us go hence'' (egeiresthe, agōmen enteuthen — rise up, let us go from here). Jesus rises to go to Gethsemane and the arrest. He goes willingly, commandingly. The discourse of chapters 15-17 may have been spoken as they walked, or before they left the room.',
   NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'John' AND c.chapter_number = 14;

-- JOHN CHAPTER 14 — BACKFILL (word_studies + cross_references)

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'μὴ ταρασσέσθω ὑμῶν ἡ καρδία', 'mē tarassesthō hymōn hē kardia', 'G5015/G2588', 'Let not your heart be troubled — present passive imperative with mē: stop being troubled (they already are). tarassō = inward agitation, the same word used of Jesus himself (11:33; 12:27; 13:21). The disciples are permitted feelings, not commanded ease.', 1),
  (1, 'πιστεύετε εἰς τὸν Θεόν καὶ εἰς ἐμὲ πιστεύετε', 'pisteuete eis ton Theon kai eis eme pisteuete', 'G4100', 'Ye believe in God, believe also in me — ambiguous grammar (both indicatives, both imperatives, or mixed). Most naturally: ''go on believing in God; go on believing in me also''. Jesus sets trust in himself on the same plane as trust in God — implicit deity claim.', 2),
  (2, 'ἐν τῇ οἰκίᾳ τοῦ πατρός μου μοναὶ πολλαί', 'en tē oikia tou patros mou monai pollai', 'G3614/G3962/G3438', 'In my Father''s house are many mansions — monē = abiding-place, dwelling (from menō). Not ''mansions'' in the grand modern sense (that is KJV-era English) but ''abodes''. Heaven has abundant room; no disciple need fear exclusion for lack of space.', 3),
  (2, 'ἑτοιμάσαι τόπον ὑμῖν', 'hetoimasai topon hymin', 'G2090/G5117', 'To prepare a place for you — topos = specific reserved location. The ascension is purposive: Jesus goes as forerunner-preparer. Echoes the priestly entrance into the holy of holies (Heb 6:20; 9:24).', 4),
  (3, 'πάλιν ἔρχομαι', 'palin erchomai', 'G3825/G2064', 'I will come again — present tense with future force: ''I am coming again''. The certainty of the parousia; the first explicit return-promise in John''s gospel.', 5),
  (3, 'παραλήμψομαι ὑμᾶς πρὸς ἐμαυτόν', 'paralēmpsomai hymas pros emauton', 'G3880', 'Receive you unto myself — paralambanō = to take alongside (as a bridegroom takes a bride, or master takes a disciple). Intimacy of the reception; not merely location transfer, but personal embrace.', 6),
  (6, 'ἐγώ εἰμι ἡ ὁδὸς', 'egō eimi hē hodos', 'G1510/G3598', 'I am the way — the fifth egō eimi ''I AM'' predication in John. hodos = road, path. Not a way-shower but the Way himself; access to the Father is a person, not a method.', 7),
  (6, 'ἡ ἀλήθεια', 'hē alētheia', 'G225', 'The truth — alētheia = reality, unveiling. Jesus does not merely teach truth; he IS the embodiment of divine reality (1:14, 17).', 8),
  (6, 'ἡ ζωή', 'hē zōē', 'G2222', 'The life — zōē = the quality of life eternal, divine life (vs. bios, biological life). The Logos has life in himself (1:4; 5:26) and gives it.', 9),
  (6, 'οὐδεὶς ἔρχεται πρὸς τὸν πατέρα εἰ μὴ δι᾽ ἐμοῦ', 'oudeis erchetai pros ton patera ei mē di'' emou', 'G3762/G3962', 'No man cometh unto the Father but by me — exclusive soteriological claim. Christ alone is the mediator (1 Tim 2:5); every other access-claim is false.', 10),
  (9, 'ὁ ἑωρακὼς ἐμὲ ἑώρακεν τὸν πατέρα', 'ho heōrakōs eme heōraken ton patera', 'G3708/G3962', 'He that hath seen me hath seen the Father — perfect tense twice: abiding vision. The Son is the exact representation of the Father (Heb 1:3); to see Christ is to see God.', 11),
  (10, 'ὁ πατὴρ ἐν ἐμοὶ μένων ποιεῖ τὰ ἔργα', 'ho patēr en emoi menōn poiei ta erga', 'G3306/G2041', 'The Father that dwelleth in me, he doeth the works — mutual indwelling of Father and Son; the Son''s works are the Father''s works, not imitative but ontologically shared activity.', 12),
  (12, 'μείζονα τούτων ποιήσει', 'meizona toutōn poiēsei', 'G3187/G4160', 'Greater works than these shall he do — not greater in miraculous intensity but in scope and fruit: post-Pentecost mission, global in reach; greater because accomplished through the ascended Christ by Spirit-empowered witnesses.', 13),
  (13, 'ὅ τι ἂν αἰτήσητε ἐν τῷ ὀνόματί μου', 'ho ti an aitēsēte en tō onomati mou', 'G154/G3686', 'Whatsoever ye shall ask in my name — en tō onomati = on the basis of who I am and what I have done. Prayer in Jesus'' name is prayer aligned with his character and mission, not a magical tagline.', 14),
  (15, 'ἐὰν ἀγαπᾶτέ με τὰς ἐντολὰς τὰς ἐμὰς τηρήσετε', 'ean agapate me tas entolas tas emas tērēsete', 'G25/G1785/G5083', 'If ye love me, keep my commandments — tēreō = to guard, watch over. Love is not sentimental affection but obedient guarding of Jesus'' entolai. Love and obedience are not rivals but inseparable.', 15),
  (16, 'ἄλλον παράκλητον', 'allon paraklēton', 'G243/G3875', 'Another Comforter — allos = another of the same kind (vs. heteros, another of a different kind). The Spirit is Christ''s counterpart — same divine office, different personal mission. paraklētos = one called alongside: advocate, helper, counsellor.', 16),
  (16, 'εἰς τὸν αἰῶνα', 'eis ton aiōna', 'G165', 'Forever — unlike Jesus'' temporary bodily absence, the Spirit''s indwelling is permanent. The new-covenant Spirit does not depart for disobedience (cf. 1 Sam 16:14) but abides in the believer always.', 17),
  (17, 'τὸ Πνεῦμα τῆς ἀληθείας', 'to Pneuma tēs alētheias', 'G4151/G225', 'The Spirit of truth — threefold in John (14:17; 15:26; 16:13). The Spirit is characterised by alētheia: he unveils reality, reveals the Father and Son, opposes the ''spirit of error'' (1 John 4:6).', 18),
  (17, 'παρ᾽ ὑμῖν μένει καὶ ἐν ὑμῖν ἔσται', 'par hymin menei kai en hymin estai', 'G3306', 'Dwelleth with you, and shall be in you — shift from para (alongside, external) to en (inside, internal). Anticipating Pentecost: the Old Testament Spirit who came upon prophets now indwells every believer.', 19),
  (18, 'οὐκ ἀφήσω ὑμᾶς ὀρφανούς', 'ouk aphēsō hymas orphanous', 'G863/G3737', 'Not leave you comfortless — orphanos = orphaned, fatherless. Rabbinic disciples were called children of their teacher; Jesus'' departure threatens to orphan them, but the Spirit maintains the Father''s presence.', 20),
  (19, 'ὅτι ἐγὼ ζῶ καὶ ὑμεῖς ζήσετε', 'hoti egō zō kai hymeis zēsete', 'G2198', 'Because I live, ye shall live also — the resurrection of Christ is the guarantee of believers'' life. His indestructible life (Heb 7:16) communicates itself to his own.', 21),
  (21, 'ἐμφανίσω αὐτῷ ἐμαυτόν', 'emphanisō autō emauton', 'G1718', 'Will manifest myself to him — emphanizō = to make visible, disclose. Post-Resurrection self-revelation to disciples, not to the world (v.22 follows). The obedient believer receives ongoing spiritual manifestations of Christ.', 22),
  (23, 'μονὴν παρ᾽ αὐτῷ ποιησόμεθα', 'monēn par autō poiēsometha', 'G3438/G4160', 'Make our abode with him — monē (as in v.2) reused: believers are not only destined for monai in the Father''s house; the Father and Son come and make monē in the believer now. Heaven and earth meet in the indwelt saint.', 23),
  (26, 'ὁ παράκλητος τὸ Πνεῦμα τὸ ἅγιον', 'ho paraklētos to Pneuma to hagion', 'G3875/G4151/G40', 'The Comforter, the Holy Ghost — first explicit identification of the Paraclete as the Holy Spirit. Sent by the Father ''in my name'' — on Jesus'' commission and authority.', 24),
  (26, 'ὑπομνήσει ὑμᾶς πάντα', 'hypomnēsei hymas panta', 'G5279', 'Bring all things to your remembrance — hypomimnēskō = to remind. The Spirit-taught recollection underwrites the apostolic gospel records; John claims divine anamnēsis for the tradition he hands on.', 25),
  (27, 'εἰρήνην τὴν ἐμὴν δίδωμι ὑμῖν', 'eirēnēn tēn emēn didōmi hymin', 'G1515/G1325', 'My peace I give unto you — eirēnē = Hebrew shalom: wholeness, right-ordering. Not the Pax Romana (superficial imperial absence of war) but Christ''s own inward tranquillity bequeathed as a farewell gift.', 26),
  (27, 'οὐ καθὼς ὁ κόσμος δίδωσιν', 'ou kathōs ho kosmos didōsin', 'G3756/G2531/G2889', 'Not as the world giveth — the world''s peace is conditional, shallow, revocable; Christ''s peace is rooted in reconciliation with God and endures through storms.', 27),
  (28, 'ὁ πατήρ μείζων μού ἐστιν', 'ho patēr meizōn mou estin', 'G3187', 'The Father is greater than I — meizōn refers to functional/economic ordering within the Trinity during the incarnation, not ontological inequality. The Son voluntarily submits in the economy of redemption (cf. Phil 2:6-7); he is fully equal in essence (10:30; 14:9).', 28),
  (30, 'ὁ τοῦ κόσμου ἄρχων', 'ho tou kosmou archōn', 'G758/G2889', 'The prince of this world — Satan (cf. 12:31; 16:11). He ''cometh'' through Judas and the arresting soldiers; yet he has ''nothing in me'' (en emoi ouk echei ouden) — no legitimate claim, no foothold of sin.', 29),
  (31, 'ἵνα γνῷ ὁ κόσμος ὅτι ἀγαπῶ τὸν πατέρα', 'hina gnō ho kosmos hoti agapō ton patera', 'G25/G3962', 'That the world may know I love the Father — the cross is Jesus'' public declaration of love for the Father, answered by perfect obedience to the entolē. Love and command are inseparable in the Son as they will be in disciples.', 30),
  (31, 'ἐγείρεσθε ἄγωμεν ἐντεῦθεν', 'egeiresthe agōmen enteuthen', 'G1453/G71', 'Arise, let us go hence — present middle imperative + hortatory subjunctive. Jesus rises decisively; the cross is embraced, not stumbled into. Whether 15-17 was spoken en route or before departing is debated; the willingness is unambiguous.', 31),
  (4, 'τὴν ὁδόν', 'tēn hodon', 'G3598', 'The way — anticipates v.6. The departure ''whither'' and the ''how'' are both known: the Father''s house via the cross-resurrection. Thomas''s confusion in v.5 sets up the climactic ego eimi.', 32),
  (11, 'διὰ τὰ ἔργα αὐτά', 'dia ta erga auta', 'G1223/G2041', 'For the very works'' sake — Jesus admits the possibility of weaker faith resting on miraculous evidence (cf. 10:38). The works witness to the Worker when the Word alone does not yet persuade.', 33),
  (17, 'ὁ κόσμος οὐ δύναται λαβεῖν', 'ho kosmos ou dynatai labein', 'G2889/G2983', 'The world cannot receive — three negations: cannot receive (dynatai labein), does not see (theōrei), does not know (ginōskei). The unbelieving world is spiritually incapable until the Spirit himself opens the eyes (16:8-11).', 34),
  (22, 'Ἰούδας οὐχ ὁ Ἰσκαριώτης', 'Ioudas ouch ho Iskariōtēs', 'G2455/G2469', 'Judas not Iscariot — likely Jude/Thaddaeus, son of James (Luke 6:16; Acts 1:13). John pointedly distinguishes him; Iscariot has already exited (13:30).', 35),
  (24, 'ὁ λόγος ὃν ἀκούετε οὐκ ἔστιν ἐμὸς', 'ho logos hon akouete ouk estin emos', 'G3056', 'The word which ye hear is not mine — the message originates from the Father; Jesus is the faithful transmitter. Rejection of Christ''s word is rejection of the Father''s word — the gravest kind of unbelief.', 36),
  (29, 'πρὶν γενέσθαι', 'prin genesthai', 'G4250/G1096', 'Before it come to pass — Jesus tells them now so that when the events occur, faith may be confirmed (not created ab novo). Prophetic prediction is apologetic scaffolding for future belief (cf. 13:19; 16:4).', 37)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'John' AND c.chapter_number = 14 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

INSERT INTO cross_references (verse_id, reference, ref_order)
SELECT v.id, x.reference, x.ref_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'John 14:27', 1),
  (1, 'John 16:33', 2),
  (1, 'Isaiah 26:3', 3),
  (1, 'Philippians 4:6-7', 4),
  (1, 'Psalm 42:11', 5),
  (2, 'Hebrews 11:10', 6),
  (2, 'Hebrews 11:14-16', 7),
  (2, 'Revelation 21:2-3', 8),
  (2, '2 Corinthians 5:1', 9),
  (3, 'Acts 1:11', 10),
  (3, '1 Thessalonians 4:16-17', 11),
  (3, 'John 17:24', 12),
  (3, 'Revelation 22:20', 13),
  (4, 'John 13:33', 14),
  (5, 'John 20:25', 15),
  (5, 'John 11:16', 16),
  (6, 'Hebrews 10:19-22', 17),
  (6, 'Acts 4:12', 18),
  (6, '1 Timothy 2:5', 19),
  (6, 'Ephesians 2:18', 20),
  (6, '1 John 5:20', 21),
  (6, 'John 10:9', 22),
  (6, 'John 1:14', 23),
  (6, 'John 11:25', 24),
  (7, 'John 8:19', 25),
